#include <stdio.h>
#include <pthread.h>

#define CAPACITY 4
#define NUM_ITEMS 10

typedef struct {
    int items[CAPACITY];
    int count;
    int head;
    int tail;
    pthread_mutex_t lock;
    pthread_cond_t not_full;
    pthread_cond_t not_empty;
} queue_t;

static void queue_init(queue_t *q) {
    q->count = 0;
    q->head = 0;
    q->tail = 0;
    pthread_mutex_init(&q->lock, NULL);
    pthread_cond_init(&q->not_full, NULL);
    pthread_cond_init(&q->not_empty, NULL);
}

static void queue_push(queue_t *q, int value) {
    pthread_mutex_lock(&q->lock);
    // your code here: wait while full, insert at tail, advance tail,
    // increment count, signal not_empty
    (void)value;
    pthread_mutex_unlock(&q->lock);
}

static int queue_pop(queue_t *q) {
    pthread_mutex_lock(&q->lock);
    // your code here: wait while empty, read from head, advance head,
    // decrement count, signal not_full, return the value
    pthread_mutex_unlock(&q->lock);
    return 0;
}

static queue_t q;

void *producer(void *arg) {
    (void)arg;
    for (int i = 1; i <= NUM_ITEMS; i++) {
        queue_push(&q, i);
    }
    return NULL;
}

void *consumer(void *arg) {
    int *sum = (int *)arg;
    *sum = 0;
    for (int i = 0; i < NUM_ITEMS; i++) {
        *sum += queue_pop(&q);
    }
    return NULL;
}

int main(void) {
    queue_init(&q);
    int sum = 0;
    pthread_t p, c;
    pthread_create(&p, NULL, producer, NULL);
    pthread_create(&c, NULL, consumer, &sum);
    pthread_join(p, NULL);
    pthread_join(c, NULL);
    printf("Total: %d\n", sum);
    return 0;
}
